(function(){"use strict";
// Minimal MCP ext-apps App shim
class App{constructor(a,b,c){this._opts=c||{};this._listeners={}}addEventListener(t,f){this._listeners[t]=f}async connect(){try{const h=(e)=>{if(!e.data||e.data.jsonrpc!=="2.0")return;if(e.data.method==="ui/notifications/tool-result"&&this._listeners.toolresult){this._listeners.toolresult(e.data.params)}};window.addEventListener("message",h);window.parent.postMessage({jsonrpc:"2.0",method:"mcp/register",id:1},"*")}catch(e){}}sendSizeChanged(s){try{window.parent.postMessage({jsonrpc:"2.0",method:"ui/sizeChanged",params:s},"*")}catch(e){}}}

function coerce(data){if(!data||typeof data!=="object")return null;var d=data;if(typeof d.audioUrl!=="string"||!d.audioUrl)return null;var str=function(v,fb){return typeof v==="string"&&v?v:fb};var num=function(v,fb){return typeof v==="number"&&isFinite(v)?v:fb};return{audioUrl:d.audioUrl,duration:num(d.duration,1),senderName:str(d.senderName,"\u6628"),colorPrimary:str(d.colorPrimary,"#94a3b8"),colorSecondary:str(d.colorSecondary,"#64748b"),colorBg:str(d.colorBg,"#0f172a"),colorBgEnd:str(d.colorBgEnd,"#1e293b"),barCount:num(d.barCount,28),bgImage:str(d.bgImage,""),customCss:str(d.customCss,""),bars:Array.isArray(d.bars)?d.bars.map(function(x){return typeof x==="number"?x:0}):[]}}
function seeded(i){var x=Math.sin(i*12.9898+78.233)*43758.5453;return x-Math.floor(x)}
var appRef=null,rendered=false;
function fmtTime(secs){var s=Math.max(0,Math.floor(secs));return Math.floor(s/60)+":"+String(s%60).padStart(2,"0")}
function render(data,platform){rendered=true;var root=document.getElementById("root");if(!root)return;root.innerHTML="";
var styleEl=document.getElementById("vc-custom-css");if(!styleEl){styleEl=document.createElement("style");styleEl.id="vc-custom-css";document.head.appendChild(styleEl)}styleEl.textContent=data.customCss||"";
var card=document.createElement("div");card.id="vc-card";var bg=data.bgImage?'center/cover no-repeat url("'+data.bgImage+'"), linear-gradient(135deg, '+data.colorBg+", "+data.colorBgEnd+")":"radial-gradient(140px 90px at 22% 50%, "+data.colorPrimary+"33, transparent 72%),radial-gradient(160px 120px at 88% 120%, "+data.colorSecondary+"22, transparent 70%),linear-gradient(135deg, "+data.colorBg+", "+data.colorBgEnd+")";
card.style.cssText="position:relative;box-sizing:border-box;width:100%;min-width:280px;min-height:92px;display:flex;align-items:center;padding:0 20px;background:"+bg+";overflow:hidden;font-family:system-ui,-apple-system,'PingFang SC','Microsoft YaHei UI',sans-serif;";
var deco=document.createElement("div");deco.id="vc-deco";deco.textContent="\u266a  \u266b";deco.style.cssText="position:absolute;right:20px;top:14px;font-size:15px;color:"+data.colorPrimary+";opacity:0.35;letter-spacing:2px;pointer-events:none;";card.appendChild(deco);
var bubble=document.createElement("div");bubble.id="vc-bubble";bubble.style.cssText="position:relative;z-index:1;box-sizing:border-box;display:inline-flex;align-items:center;gap:10px;width:auto;max-width:calc(100% - 8px);background:linear-gradient(135deg, rgba(0,0,0,0.34), rgba(0,0,0,0.18));border:1px solid "+data.colorPrimary+"33;border-radius:16px;padding:8px 14px;box-shadow:0 3px 12px rgba(0,0,0,0.28);cursor:pointer;user-select:none;backdrop-filter:blur(2px);";
var btn=document.createElement("div");btn.id="vc-play";btn.style.cssText="width:30px;height:30px;border-radius:50%;flex-shrink:0;background:linear-gradient(135deg, "+data.colorPrimary+", "+data.colorSecondary+");display:flex;align-items:center;justify-content:center;box-shadow:0 2px 6px "+data.colorPrimary+"55;";
btn.innerHTML='<svg class="i-play" width="13" height="13" viewBox="0 0 24 24" fill="white"><path d="M8 5v14l11-7z"/></svg><svg class="i-pause" width="13" height="13" viewBox="0 0 24 24" fill="white" style="display:none"><path d="M6 4h4v16H6zM14 4h4v16h-4z"/></svg>';
var iPlay=btn.querySelector(".i-play"),iPause=btn.querySelector(".i-pause");
var col=document.createElement("div");col.id="vc-col";col.style.cssText="display:flex;flex-direction:column;gap:3px;";
var wave=document.createElement("div");wave.id="vc-wave";wave.style.cssText="display:flex;align-items:center;gap:2px;height:22px;width:auto;";
var barsArr=[];var real=data.bars&&data.bars.length>0?data.bars:null;var n=real?real.length:Math.max(12,Math.min(60,Math.round(data.duration*3.2)));
for(var i=0;i<n;i++){var bar=document.createElement("div");var pos=i/n;var env=Math.sin(pos*Math.PI)*0.55+0.45;var h=real?Math.max(10,Math.min(100,real[i]*100)):Math.max(14,Math.min(100,(0.28+seeded(i)*0.72)*env*100));bar.style.cssText="width:3px;height:"+h+"%;border-radius:1.5px;flex-shrink:0;background:rgba(255,255,255,0.28);transition:background 0.12s;";wave.appendChild(bar);barsArr.push(bar)}
var labels=document.createElement("div");labels.id="vc-labels";labels.style.cssText="display:flex;justify-content:space-between;align-items:center;";
var timeEl=document.createElement("span");timeEl.id="vc-time";timeEl.textContent="0:00";timeEl.style.cssText="font-size:9px;color:"+data.colorPrimary+";font-weight:600;";
var durEl=document.createElement("span");durEl.id="vc-dur";durEl.textContent=data.duration+'"';durEl.style.cssText="font-size:9px;color:rgba(255,255,255,0.45);";
labels.append(timeEl,durEl);col.append(wave,labels);
var audio=document.createElement("audio");audio.preload="auto";audio.src=data.audioUrl;
bubble.append(btn,col,audio);card.appendChild(bubble);
var nameEl=document.createElement("div");nameEl.id="vc-name";nameEl.textContent=data.senderName+" \u00b7 \u8bed\u97f3";nameEl.style.cssText="position:absolute;left:22px;bottom:12px;font-size:9px;color:rgba(255,255,255,0.4);pointer-events:none;";
card.appendChild(nameEl);root.appendChild(card);
var playing=false,raf=0;
var paint=function(on,b){if(on){b.style.background="linear-gradient(to top, "+data.colorPrimary+", "+data.colorSecondary+")";b.style.boxShadow="0 0 3px "+data.colorPrimary+"44"}else{b.style.background="rgba(255,255,255,0.28)";b.style.boxShadow="none"}};
var tick=function(){if(!playing)return;var prog=audio.currentTime/(audio.duration||data.duration||1);var upto=Math.floor(prog*barsArr.length);barsArr.forEach(function(b,i){paint(i<upto,b)});timeEl.textContent=fmtTime(audio.currentTime);raf=requestAnimationFrame(tick)};
var toggle=function(){if(playing){audio.pause();playing=false;iPlay.style.display="block";iPause.style.display="none";cancelAnimationFrame(raf)}else{audio.play().then(function(){playing=true;iPlay.style.display="none";iPause.style.display="block";tick()}).catch(function(e){console.warn("[voice] playback failed:",e)})}};
bubble.addEventListener("click",toggle);
audio.addEventListener("ended",function(){playing=false;iPlay.style.display="block";iPause.style.display="none";cancelAnimationFrame(raf);barsArr.forEach(function(b){paint(false,b)});timeEl.textContent="0:00"});
if(platform==="claude"){var reportH=function(){var h=Math.ceil(card.getBoundingClientRect().height);if(h<=0)return;document.documentElement.style.height=h+"px";document.body.style.height=h+"px";if(appRef){try{appRef.sendSizeChanged({width:Math.ceil(window.innerWidth),height:h})}catch(e){}}};requestAnimationFrame(function(){reportH();requestAnimationFrame(reportH);setTimeout(reportH,200)})}}
function showError(msg){if(rendered)return;var root=document.getElementById("root");if(root)root.innerHTML='<div style="color:#b8aabb;font-size:13px;padding:10px;">'+msg+"</div>"}
function renderToolResult(params,platform){var data=coerce(params&&params.structuredContent);if(!data&&Array.isArray(params&&params.content)){for(var i=0;i<params.content.length;i++){var block=params.content[i];if(block.type==="text"&&block.text){try{data=coerce(JSON.parse(block.text))}catch(e){}if(data)break}}}if(data)render(data,platform)}
function tryChatGpt(){if(!window.openai)return;var apply=function(){var data=coerce(window.openai&&window.openai.toolOutput);if(data)render(data,"chatgpt")};apply();window.addEventListener("openai:set_globals",apply);window.addEventListener("message",function(event){if(event.source!==window.parent)return;var message=event.data;if(!message||message.jsonrpc!=="2.0")return;if(message.method!=="ui/notifications/tool-result")return;renderToolResult(message.params,"chatgpt")})}
function tryMcpApps(){try{var app=new App({name:"voice-mcp",version:"1.0.0"},{},{autoResize:false});appRef=app;app.addEventListener("toolresult",function(params){renderToolResult(params,"claude")});app.connect()}catch(e){console.debug("[voice] MCP Apps connect skipped:",e)}}
function boot(){tryChatGpt();tryMcpApps();setTimeout(function(){showError("\u7b49\u5f85\u8bed\u97f3\u6570\u636e\u2026")},4000)}
boot()})();
